"      // Check query parameter deep linking
      const targetModule = urlParams.get('module');
      if (targetModule === 'customizer') {
        // Deep link to the Theme Customizer — auto-open it
        setTimeout(() => {
          const customizeBtn = document.getElementById('customizeBtn');
          if (customizeBtn) {
            customizeBtn.click();
            // If tab=pages specified, auto-switch to Pages tab
            const targetTab = urlParams.get('tab');
            if (targetTab === 'pages') {
              setTimeout(() => {
                if (typeof showTab === 'function') showTab('Pages');
              }, 400);
            }
          }
        }, 800);
      } else if (targetModule) {
        selectedModule = normalizeModuleKey(targetModule);
        switchView('modules');
      }"

